# Handle encoding safely
def safe_read(filepath):
    """Try UTF-8 first, fall back to Latin-1."""
    for encoding in ['utf-8', 'latin-1']:
        try:
            with open(filepath, 'r', encoding=encoding) as f:
                content = f.read()
            print(f"Read with {encoding}")
            return content
        except UnicodeDecodeError:
            continue
    # Last resort: read as binary
    with open(filepath, 'rb') as f:
        return f.read().decode('utf-8', errors='replace')

import os

def safe_read_file(filepath):
    """Read a file with comprehensive error handling."""
    try:
        if not os.path.exists(filepath):
            return None, f"Not found: {filepath}"
        with open(filepath, 'r', encoding='utf-8') as f:
            return f.read(), None
    except PermissionError:
        return None, f"Permission denied: {filepath}"
    except UnicodeDecodeError:
        return None, f"Encoding error: {filepath}"
    except OSError as e:
        return None, f"OS error: {e}"

